class Solution:
    def topKFrequent(self, nums, k):
        from collections import Counter
        counts = Counter(nums)
        buckets = [[] for _ in range(len(nums) + 1)]
        for v, c in counts.items():
            buckets[c].append(v)
        out = []
        for c in range(len(nums), 0, -1):
            for v in buckets[c]:
                out.append(v)
                if len(out) == k:
                    return out
        return out

